@@ -0,0 +1,15 @@
+{
+  "name": "tab_basic",
+  "description": "HT (0x09) advances cursor to next tab stop at column 8",
+  "initial_size": [20, 3],
+  "input_bytes_hex": "41420958",
+  "comment": "Print AB at (0,0)-(0,1), TAB to col 8, print X at (0,8). Cursor at (0,9).",
+  "expected": {
+    "cursor": { "row": 0, "col": 9 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 1, "char": "B" },
+      { "row": 0, "col": 8, "char": "X" }
+    ]
+  }
+}

@@ -0,0 +1,13 @@
+{
+  "name": "el_left",
+  "description": "CSI 1 K erases from start of line to cursor inclusive",
+  "initial_size": [10, 3],
+  "input_bytes_hex": "41424344451b5b313b34481b5b314b",
+  "comment": "Print ABCDE at (0,0)-(0,4), CUP(1,4) to (0,3), EL(1) erases cols 0..3 inclusive. Only E remains.",
+  "expected": {
+    "cursor": { "row": 0, "col": 3 },
+    "cells": [
+      { "row": 0, "col": 4, "char": "E" }
+    ]
+  }
+}
